import java.util.*;

public class BruteForce {
    public static long getSpecialSubarrays(int[] efficiency, int k) {
        int n = efficiency.length;
        int target = efficiency[k - 1]; // converting 1-based index to 0-based
        long count = 0;

        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j += 2) { // step by 2 ensures odd length subarrays
                int len = j - i + 1;
                int[] sub = new int[len];
                System.arraycopy(efficiency, i, sub, 0, len);
                Arrays.sort(sub);

                if (sub[len / 2] == target) {
                    count++;
                }
            }
        }
        return count;
    }

