import java.util.*;
import java.io.*;

public class Solution {
    public static long getSpecialSubarrays(int[] efficiency, int k) {
        int n = efficiency.length;
        int u = efficiency[k - 1]; // Converting 1-based index to 0-based index

        // Transform array: < u -> -1, == u -> 0, > u -> +1
        int[] b = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            if (efficiency[i - 1] < u) b[i] = -1;
            else if (efficiency[i - 1] == u) b[i] = 0;
            else b[i] = 1;
        }

        // Maps to track prefix sums frequencies at even and odd indices
        Map<Long, Long> freqEven = new HashMap<>();
        Map<Long, Long> freqOdd = new HashMap<>();

        long prefixSum = 0;
        long count = 0;

        // Base case: prefix sum 0 at index 0 (even index)
        freqEven.put(0L, 1L);

        for (int i = 1; i <= n; i++) {
            prefixSum += b[i];
            if (i % 2 == 1) {
                // Odd index: look for the same prefix sum at even indices in the past
                count += freqEven.getOrDefault(prefixSum, 0L);
                freqOdd.put(prefixSum, freqOdd.getOrDefault(prefixSum, 0L) + 1);
            } else {
                // Even index: look for the same prefix sum at odd indices in the past
                count += freqOdd.getOrDefault(prefixSum, 0L);
                freqEven.put(prefixSum, freqEven.getOrDefault(prefixSum, 0L) + 1);
            }
        }

        return count;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] first = br.readLine().trim().split("\\s+");
        if(first[0].isEmpty()) return;

        int n = Integer.parseInt(first[0]);
        int k = Integer.parseInt(first[1]);

        int[] efficiency = new int[n];
        String[] arr = br.readLine().trim().split("\\s+");
        for (int i = 0; i < n; i++) {
            efficiency[i] = Integer.parseInt(arr[i]);
        }

        System.out.println(getSpecialSubarrays(efficiency, k));
    }
}
